UPDATE public.email_drip_steps
SET subject = 'Спасибо за регистрацию в ReAge',
    preheader = 'Коротко о том, как всё устроено и что будет дальше',
    cta_label = NULL,
    cta_url = NULL,
    body_markdown = E'Здравствуйте, {{first_name}}.\n\nЯ Алексей, основатель ReAge. Хочу лично поблагодарить вас за регистрацию и в нескольких абзацах рассказать, как у нас всё устроено.\n\nИдея простая: раз в три месяца медсестра приезжает к вам домой и берёт кровь. Лаборатория делает развёрнутый набор биомаркеров — гормоны, метаболизм, воспаление, дефициты. Мы считаем ваш биологический возраст и его динамику. Врач разбирает результаты и даёт персональные рекомендации: что поправить в питании, какие добавки и в каких дозах, какие повторные показатели отслеживать.\n\nВ ближайший месяц я буду присылать короткие письма без воды. Расскажу, почему «нормальные» анализы часто ничего не значат, какие показатели первыми сигналят о старении и как читать собственные результаты.\n\nЕсли появятся вопросы — просто ответьте на это письмо, мы отвечаем сами.\n\nДо связи,\nАлексей и команда ReAge'
WHERE series_id = 'f68e21a2-7a7b-482a-a1bc-67ddd8d8acbe' AND order_index = 1;